// Filter leads that are due for their next nurture email today
const leads = $input.all();
const now = new Date();
const results = [];

for (const item of leads) {
  const lead = item.json;

  // Skip if status is engaged, closed, or unsubscribed
  if (['engaged', 'closed', 'unsubscribed', 'nurture_complete'].includes(lead.status)) {
    continue;
  }

  const stage = parseInt(lead.nurture_stage) || 0;
  const submittedAt = new Date(lead.submitted_at);
  const daysSinceSubmission = Math.floor((now - submittedAt) / (1000 * 60 * 60 * 24));

  // Nurture schedule: stage → day threshold
  const schedule = {
    0: 2,   // Stage 1 email on day 2
    1: 5,   // Stage 2 email on day 5
    2: 9,   // Stage 3 email on day 9
    3: 14,  // Stage 4 email on day 14
    4: 21,  // Stage 5 email on day 21
    5: 30   // Stage 6 email on day 30 (cool leads only)
  };

  const nextDay = schedule[stage];

  // No more stages
  if (nextDay === undefined) continue;

  // Stage 6 is only for cool leads
  if (stage === 5 && lead.tier !== 'cool') continue;

  // Check if today is the day (or past due)
  if (daysSinceSubmission >= nextDay) {
    // Check we haven't already sent today
    const lastSent = lead.last_email_sent ? new Date(lead.last_email_sent) : null;
    if (lastSent && lastSent.toDateString() === now.toDateString()) {
      continue; // Already sent today
    }

    results.push({
      json: {
        ...lead,
        next_stage: stage + 1,
        days_since_submission: daysSinceSubmission
      }
    });
  }
}

if (results.length === 0) {
  // Return empty to stop the workflow
  return [];
}

return results;

// Prepare the update data for Google Sheets
const lead = $input.first().json;
const now = new Date().toISOString();

return [{
  json: {
    lead_id: lead.lead_id,
    nurture_stage: lead.next_stage,
    last_email_sent: now,
    status: lead.next_stage >= 6 ? 'nurture_complete' : lead.status
  }
}];
